import type { SolidComponent } from '@/type';
import { cn } from '@/utils/cn';
import { getColor } from '@/utils/helper';
import { createVirtualizer } from '@tanstack/solid-virtual';
import { cva, type VariantProps } from 'class-variance-authority';
import Check from 'lucide-solid/icons/check';
import ChevronDown from 'lucide-solid/icons/chevron-down';
import Search from 'lucide-solid/icons/search';
import X from 'lucide-solid/icons/x';
import {
  createEffect,
  createMemo,
  createSignal,
  For,
  mergeProps,
  on,
  Show,
  type Component,
  type JSXElement,
} from 'solid-js';
import { Dropdown } from '../dropdown';
import type {
  FlattenOptionData,
  LabeledValue,
  OptGroupType,
  SelectBaseProps,
  SelectFieldNames,
  SelectOptionType,
  SelectProps,
  SelectValue,
  ShowSearchConfig,
  TagRenderProps,
} from './select.types';

const selectVariants = cva('sel01', {
  variants: {
    variant: {
      outline: 'sel07',
      filled: 'sel09',
      borderless: 'sel08',
      underlined: 'sel10',
    },
    size: {
      lg: 'sel06',
      md: 'sel05',
      sm: 'sel04',
    },
    color: {
      neutral: 'input-neutral',
      primary: 'input-primary',
      secondary: 'input-secondary',
      accent: 'input-accent',
      info: 'input-info',
      success: 'input-success',
      warning: 'input-warning',
      error: 'input-error',
    },
  },
});
export type SelectVariantsProps = VariantProps<typeof selectVariants>;

type SelectTagProps = {
  tag: { value: string | number; label: SolidComponent; closable: boolean };
  removeIcon?: JSXElement;
  tagRender?: (props: TagRenderProps) => JSXElement;
  onRemove: (value: string | number, e: MouseEvent) => void;
};

const SelectTag: Component<SelectTagProps> = props => {
  if (props.tagRender) {
    return props.tagRender({
      label: props.tag.label,
      value: props.tag.value,
      closable: props.tag.closable,
      onClose: () => props.onRemove(props.tag.value, new MouseEvent('click')),
    }) as JSXElement;
  }

  return (
    <span class="sel17">
      <span class="sel18">{props.tag.label as Element}</span>
      <Show when={props.tag.closable}>
        <span class="sel19" onClick={e => props.onRemove(props.tag.value, e)}>
          {props.removeIcon ? (
            (props.removeIcon as Element)
          ) : (
            <X class="m-auto" size={12} stroke-width={3} />
          )}
        </span>
      </Show>
    </span>
  );
};

const InnerTooltip: Component<{ content: JSXElement; children: JSXElement }> = props => {
  return (
    <span class="sel42">
      {props.children}
      <span class="sel43">
        <span class="sel44">{props.content}</span>
      </span>
    </span>
  );
};

function resolveFieldNames(fn?: SelectFieldNames) {
  return {
    label: fn?.label ?? 'label',
    value: fn?.value ?? 'value',
    options: fn?.options ?? 'options',
    groupLabel: fn?.groupLabel ?? 'label',
  };
}

function getField(option: any, field: string): any {
  return option?.[field];
}

interface FlatOption {
  label: SolidComponent;
  value: string | number;
  disabled?: boolean;
  class?: string;
  title?: string;
  groupLabel?: SolidComponent;
  raw: any;
}

function flattenOptions(
  options: (SelectOptionType | OptGroupType)[] | undefined,
  fieldNames: ReturnType<typeof resolveFieldNames>,
): FlatOption[] {
  if (!options) return [];
  const result: FlatOption[] = [];
  for (const opt of options) {
    const subOptions = getField(opt, fieldNames.options) as SelectOptionType[] | undefined;
    if (subOptions && Array.isArray(subOptions)) {
      const groupLabel = getField(opt, fieldNames.groupLabel) as SolidComponent;
      for (const sub of subOptions) {
        result.push({
          label: getField(sub, fieldNames.label) as SolidComponent,
          value: getField(sub, fieldNames.value) as string | number,
          disabled: sub.disabled,
          class: sub.class,
          title: sub.title,
          groupLabel,
          raw: sub,
        });
      }
    } else {
      result.push({
        label: getField(opt, fieldNames.label) as SolidComponent,
        value: getField(opt, fieldNames.value) as string | number,
        disabled: (opt as SelectOptionType).disabled,
        class: (opt as SelectOptionType).class,
        title: (opt as SelectOptionType).title,
        groupLabel: undefined,
        raw: opt,
      });
    }
  }
  return result;
}

interface OptionGroup {
  groupLabel?: SolidComponent;
  items: FlatOption[];
}

function regroupFlatOptions(flatOptions: FlatOption[]): OptionGroup[] {
  const groups: OptionGroup[] = [];
  for (const opt of flatOptions) {
    const last = groups[groups.length - 1];
    if (last && last.groupLabel === opt.groupLabel) {
      last.items.push(opt);
    } else {
      groups.push({ groupLabel: opt.groupLabel, items: [opt] });
    }
  }
  return groups;
}

function extractValue(v: string | number | LabeledValue | undefined): string | number | undefined {
  if (v === undefined || v === null) return undefined;
  if (typeof v === 'object' && 'value' in v) return v.value;
  return v as string | number;
}

function extractValues(
  v: string | string[] | number | number[] | LabeledValue | LabeledValue[] | undefined,
): (string | number)[] {
  if (v === undefined || v === null) return [];
  if (Array.isArray(v)) {
    return v.map(item => extractValue(item)!).filter(x => x !== undefined);
  }
  const single = extractValue(v as string | number | LabeledValue);
  return single !== undefined ? [single] : [];
}

export const Select: Component<SelectProps> = p => {
  p = mergeProps(
    {
      color: 'error' as const,
      size: 'md' as const,
      variant: 'outline' as const,
      disabled: false,
      loading: false,
      placement: 'bottom' as const,
      listHeight: 256,
      virtual: false,
      defaultActiveFirstOption: false,
      notFoundContent: 'Not Found' as SolidComponent,
      labelInValue: false,
      placeholder: 'Select...',
      blockScroll: true,
    } as SelectBaseProps,
    p,
  );

  const fieldNames = createMemo(() => resolveFieldNames(p.fieldNames));

  const isMultiple = createMemo(() => p.mode === 'multiple');
  const allowCustomValue = createMemo(() => isMultiple() && !!(p as any).allowCustomValue);

  const showSearchEnabled = createMemo(() => {
    if (typeof p.showSearch === 'boolean') return p.showSearch;
    if (typeof p.showSearch === 'object') return true;

    return isMultiple();
  });

  const searchConfig = createMemo((): ShowSearchConfig => {
    const base: ShowSearchConfig = {
      autoClearSearchValue: true,
      filterOption: true,
      optionFilterProp: 'value',
    };
    if (typeof p.showSearch === 'object') {
      return { ...base, ...p.showSearch };
    }
    return base;
  });

  const [internalValue, setInternalValue] = createSignal<(string | number)[]>(
    extractValues(p.defaultValue),
  );
  const [isOpen, setIsOpen] = createSignal(p.defaultOpen ?? false);
  const [searchText, setSearchText] = createSignal('');
  const [activeIndex, setActiveIndex] = createSignal(-1);

  const selectedValues = createMemo(() => {
    if (p.value !== undefined) {
      return extractValues(p.value);
    }
    return internalValue();
  });

  const dropdownOpen = createMemo(() => {
    if (p.open !== undefined) {
      return p.open as boolean;
    }
    return isOpen();
  });

  const controlledSearchValue = createMemo(() => {
    const cfg = searchConfig();
    if (cfg.searchValue !== undefined) return cfg.searchValue;
    return undefined;
  });

  const currentSearchText = createMemo(() => {
    return controlledSearchValue() ?? searchText();
  });

  let inputRef: HTMLInputElement | undefined;
  let selectRootRef: HTMLDivElement | undefined;
  let triggerRef: HTMLDivElement | undefined;
  const [listRef, setListRef] = createSignal<HTMLDivElement | null>(null);

  const allFlatOptions = createMemo(() => flattenOptions(p.options, fieldNames()));

  const allOptionsWithCustom = createMemo(() => {
    const flat = allFlatOptions();
    if (!allowCustomValue()) return flat;
    const existingValues = new Set(flat.map(o => o.value));
    const customOpts: FlatOption[] = [];
    for (const val of selectedValues()) {
      if (!existingValues.has(val)) {
        customOpts.push({
          label: String(val),
          value: val,
          disabled: false,
          class: undefined,
          title: undefined,
          groupLabel: undefined,
          raw: { label: String(val), value: val },
        });
      }
    }
    return [...flat, ...customOpts];
  });

  const optionMap = createMemo(() => {
    const map = new Map<string | number, FlatOption>();
    for (const opt of allOptionsWithCustom()) {
      map.set(opt.value, opt);
    }
    return map;
  });

  const filteredOptions = createMemo(() => {
    const all = allOptionsWithCustom();
    const text = currentSearchText();
    if (!text || !showSearchEnabled()) return all;

    const cfg = searchConfig();
    if (cfg.filterOption === false) return all;

    let filtered: FlatOption[];
    if (typeof cfg.filterOption === 'function') {
      filtered = all.filter(opt =>
        (cfg.filterOption as Function)(text, opt.raw as SelectOptionType),
      );
    } else {
      const filterProps = Array.isArray(cfg.optionFilterProp)
        ? cfg.optionFilterProp
        : [cfg.optionFilterProp ?? 'value'];
      const lowerText = text.toLowerCase();
      filtered = all.filter(opt => {
        return filterProps.some(prop => {
          const val = getField(opt.raw, prop) ?? (prop === 'label' ? opt.label : opt.value);
          return String(val ?? '')
            .toLowerCase()
            .includes(lowerText);
        });
      });
    }

    if (cfg.filterSort) {
      const sortFn = cfg.filterSort;
      filtered.sort((a, b) =>
        sortFn(a.raw as SelectOptionType, b.raw as SelectOptionType, { searchValue: text }),
      );
    }

    return filtered;
  });

  const groupedForRender = createMemo(() => {
    const text = currentSearchText();
    if (text && showSearchEnabled()) {
      return [{ groupLabel: undefined, items: filteredOptions() }] as OptionGroup[];
    }
    return regroupFlatOptions(allOptionsWithCustom());
  });

  type RenderItem =
    | { type: 'group'; groupLabel: SolidComponent }
    | { type: 'option'; option: FlatOption; flatIdx: number };

  const flatRenderList = createMemo((): RenderItem[] => {
    const groups = groupedForRender();
    const result: RenderItem[] = [];
    let flatIdx = 0;
    for (const group of groups) {
      if (group.groupLabel !== undefined) {
        result.push({ type: 'group', groupLabel: group.groupLabel });
      }
      for (const item of group.items) {
        result.push({ type: 'option', option: item, flatIdx });
        flatIdx++;
      }
    }
    return result;
  });

  const ITEM_HEIGHT = 32;
  const GROUP_LABEL_HEIGHT = 28;

  const virtualizer = createVirtualizer({
    get count() {
      return flatRenderList().length;
    },
    getScrollElement: () => listRef(),
    estimateSize: (index: number) => {
      const item = flatRenderList()[index];
      return item?.type === 'group' ? GROUP_LABEL_HEIGHT : ITEM_HEIGHT;
    },
    overscan: 2,
  });

  const selectedValuesSet = createMemo(() => new Set(selectedValues()));

  const isSelected = (val: string | number) => {
    return selectedValuesSet().has(val);
  };

  const isMaxReached = createMemo(() => {
    if (!isMultiple()) return false;
    const max = p.maxCount as number | undefined;
    if (max === undefined) return false;
    return selectedValues().length >= max;
  });

  // Set for a brief window after openDropdown() to suppress spurious focusout events
  // that fire when SolidJS re-renders the DOM (inserting dropdown content causes
  // the focused trigger div to receive a focusout with relatedTarget=null before
  // the search input is mounted and re-focused via queueMicrotask).
  let suppressBlurUntil = 0;

  const openDropdown = () => {
    if (p.disabled) return;
    suppressBlurUntil = performance.now() + 150;
    if (p.open === undefined) {
      setIsOpen(true);
    }
    p.onOpenChange?.(true);
  };

  const closeDropdown = () => {
    if (p.open === undefined) {
      setIsOpen(false);
    }
    setListRef(null);
    p.onOpenChange?.(false);

    if (showSearchEnabled()) {
      setSearchText('');
      searchConfig().onSearch?.('');
    }
  };

  const toggleDropdown = () => {
    if (dropdownOpen()) {
      closeDropdown();
    } else {
      openDropdown();
    }
  };

  const buildOutputValue = (values: (string | number)[]): SelectValue => {
    const map = optionMap();
    if (isMultiple()) {
      if (p.labelInValue) {
        return values.map(v => {
          const opt = map.get(v);
          return {
            value: v,
            label: opt?.label ?? String(v),
          } as LabeledValue;
        });
      }
      return values as string[] | number[];
    }

    const val = values[0];
    if (val === undefined) return undefined as any;
    if (p.labelInValue) {
      const opt = map.get(val);
      return {
        value: val,
        label: opt?.label ?? String(val),
      } as LabeledValue;
    }
    return val;
  };

  const buildOutputOption = (
    values: (string | number)[],
  ): SelectOptionType | SelectOptionType[] => {
    const map = optionMap();
    if (isMultiple()) {
      return values.map(v => {
        const opt = map.get(v);
        return (opt?.raw as SelectOptionType) ?? { value: v, label: String(v) };
      });
    }
    const val = values[0];
    const opt = map.get(val);
    return (opt?.raw as SelectOptionType) ?? { value: val, label: String(val) };
  };

  const handleSelect = (optValue: string | number) => {
    const opt = optionMap().get(optValue);
    const rawOpt = (opt?.raw as SelectOptionType) ?? {
      value: optValue,
      label: String(optValue),
    };

    if (isMultiple()) {
      const current = selectedValues();
      let newValues: (string | number)[];

      if (current.includes(optValue)) {
        newValues = current.filter(v => v !== optValue);
        const deselectVal = p.labelInValue
          ? ({ value: optValue, label: opt?.label ?? String(optValue) } as LabeledValue)
          : optValue;
        p.onDeselect?.(deselectVal);
      } else {
        if (isMaxReached()) return;
        newValues = [...current, optValue];
        const selectVal = p.labelInValue
          ? ({ value: optValue, label: opt?.label ?? String(optValue) } as LabeledValue)
          : optValue;
        p.onSelect?.(selectVal, rawOpt);
      }

      if (p.value === undefined) {
        setInternalValue(newValues);
      }
      p.onChange?.(buildOutputValue(newValues), buildOutputOption(newValues));

      if (searchConfig().autoClearSearchValue !== false) {
        setSearchText('');
        searchConfig().onSearch?.('');
      }
    } else {
      const newValues = [optValue];
      const selectVal = p.labelInValue
        ? ({ value: optValue, label: opt?.label ?? String(optValue) } as LabeledValue)
        : optValue;
      p.onSelect?.(selectVal, rawOpt);

      if (p.value === undefined) {
        setInternalValue(newValues);
      }
      p.onChange?.(buildOutputValue(newValues), buildOutputOption(newValues));
      closeDropdown();
      setSearchText('');
    }
  };

  const handleClear = (e: MouseEvent) => {
    e.stopPropagation();
    e.preventDefault();
    if (p.value === undefined) {
      setInternalValue([]);
    }
    p.onClear?.();
    p.onChange?.(isMultiple() ? [] : (undefined as any), isMultiple() ? [] : (undefined as any));
    setSearchText('');
  };

  const handleRemoveTag = (val: string | number, e?: MouseEvent) => {
    e?.stopPropagation();
    e?.preventDefault();
    const current = selectedValues();
    const newValues = current.filter(v => v !== val);

    const opt = optionMap().get(val);
    const deselectVal = p.labelInValue
      ? ({ value: val, label: opt?.label ?? String(val) } as LabeledValue)
      : val;
    p.onDeselect?.(deselectVal);

    if (p.value === undefined) {
      setInternalValue(newValues);
    }
    p.onChange?.(buildOutputValue(newValues), buildOutputOption(newValues));
  };

  const handleKeyDown = (e: KeyboardEvent) => {
    if (p.disabled) return;
    p.onInputKeyDown?.(e);

    const opts = filteredOptions();

    switch (e.key) {
      case 'ArrowDown': {
        e.preventDefault();
        if (!dropdownOpen()) {
          openDropdown();
          return;
        }
        let next = activeIndex() + 1;
        while (next < opts.length) {
          const opt = opts[next];
          if (!opt.disabled && (!isMaxReached() || isSelected(opt.value))) {
            break;
          }
          next++;
        }
        if (next < opts.length) {
          setActiveIndex(next);
          const val = p.labelInValue
            ? ({ value: opts[next].value, label: opts[next].label } as LabeledValue)
            : opts[next].value;
          p.onActive?.(val);
          scrollActiveIntoView(next);
        }
        break;
      }
      case 'ArrowUp': {
        e.preventDefault();
        if (!dropdownOpen()) {
          openDropdown();
          return;
        }
        let prev = activeIndex() === -1 ? opts.length - 1 : activeIndex() - 1;
        while (prev >= 0) {
          const opt = opts[prev];
          if (!opt.disabled && (!isMaxReached() || isSelected(opt.value))) {
            break;
          }
          prev--;
        }
        if (prev >= 0) {
          setActiveIndex(prev);
          const val = p.labelInValue
            ? ({ value: opts[prev].value, label: opts[prev].label } as LabeledValue)
            : opts[prev].value;
          p.onActive?.(val);
          scrollActiveIntoView(prev);
        }
        break;
      }
      case 'Enter':
      case ' ': {
        e.preventDefault();
        if (!dropdownOpen()) {
          openDropdown();
          return;
        }
        if (e.key === ' ' && showSearchEnabled()) break;
        const idx = activeIndex();
        if (idx >= 0 && idx < opts.length) {
          const opt = opts[idx];
          if (!opt.disabled) {
            handleSelect(opt.value);
          }
        } else if (allowCustomValue() && currentSearchText().trim()) {
          const tag = currentSearchText().trim();
          handleSelect(tag);
        }
        break;
      }
      case 'Escape': {
        e.preventDefault();
        closeDropdown();
        triggerRef?.focus();
        break;
      }
      case 'Backspace': {
        if (isMultiple() && currentSearchText() === '') {
          const vals = selectedValues();
          if (vals.length > 0) {
            handleRemoveTag(vals[vals.length - 1]);
          }
        }
        break;
      }
      case 'Tab': {
        closeDropdown();
        break;
      }
    }
  };

  const scrollActiveIntoView = (flatIdx: number) => {
    if (p.virtual) {
      const list = flatRenderList();
      const renderIdx = list.findIndex(item => item.type === 'option' && item.flatIdx === flatIdx);
      if (renderIdx >= 0) {
        virtualizer.scrollToIndex(renderIdx, { align: 'auto' });
      }
      return;
    }

    const el = listRef();
    if (!el) return;
    const items = el.querySelectorAll('[data-option-index]');
    const item = items[flatIdx] as HTMLElement | undefined;
    if (item) {
      item.scrollIntoView({ block: 'nearest' });
    }
  };

  const scrollToFirstSelected = () => {
    const vals = selectedValues();
    if (vals.length === 0) return;

    const firstSelectedValue = vals[0];
    const opts = filteredOptions();
    const flatIdx = opts.findIndex(o => o.value === firstSelectedValue);
    if (flatIdx < 0) return;

    if (p.virtual) {
      const list = flatRenderList();
      const renderIdx = list.findIndex(item => item.type === 'option' && item.flatIdx === flatIdx);
      if (renderIdx >= 0) {
        virtualizer.scrollToIndex(renderIdx, { align: 'start' });
      }
    } else {
      const el = listRef();
      if (!el) return;
      const item = el.querySelector(`[data-option-index="${flatIdx}"]`) as HTMLElement | null;
      if (item) {
        item.scrollIntoView({ block: 'nearest' });
      }
    }
  };

  const handleSearchInput = (e: InputEvent) => {
    const target = e.target as HTMLInputElement;
    const val = target.value;

    if (controlledSearchValue() === undefined) {
      setSearchText(val);
    }
    searchConfig().onSearch?.(val);

    if (!dropdownOpen()) {
      openDropdown();
    }
  };

  const handleFocus = (e: FocusEvent) => {
    // Only fix scroll when the trigger div (not the search input) receives focus.
    // The trigger div has offsetTop=0 relative to .dropdown (position:relative), which
    // causes Chromium to scroll the page to 0 when focusing it (a browser quirk).
    // We listen for the next scroll event and immediately restore the position.
    if (e.target === triggerRef) {
      const scrollX = window.scrollX;
      const scrollY = window.scrollY;
      // Chromium scrolls the page when focusing triggerRef because its offsetTop=0
      // relative to the .dropdown positioned parent (a browser quirk). We restore after
      // the focus-scroll completes by waiting for the scroll event, then deferring one rAF
      // so the browser's internal focus-scroll is truly done before we override it.
      const restoreScroll = () =>
        requestAnimationFrame(() => requestAnimationFrame(() => window.scrollTo(scrollX, scrollY)));
      window.addEventListener('scroll', restoreScroll, { once: true, passive: false });
      setTimeout(() => window.removeEventListener('scroll', restoreScroll), 200);
    }
    p.onFocus?.(e);
  };

  const handleBlur = (e: FocusEvent) => {
    const related = e.relatedTarget as HTMLElement | null;
    if (related && selectRootRef?.contains(related)) return;
    if (related?.closest('.nd-content')) return;
    // Suppress spurious focusout that fires immediately after openDropdown() while
    // SolidJS is re-rendering the DOM (before the search input is mounted and focused).
    if (performance.now() < suppressBlurUntil) return;
    p.onBlur?.(e);
    closeDropdown();
  };

  const selectedLabel = createMemo((): JSXElement => {
    if (isMultiple()) return null;
    const vals = selectedValues();
    if (vals.length === 0) return null;
    const val = vals[0];
    const opt = optionMap().get(val);

    if (p.labelRender) {
      return p.labelRender({
        value: val,
        label: opt?.label ?? String(val),
        key: String(val),
      });
    }

    return (opt?.label as Element) ?? String(val);
  });

  interface TagInfo {
    value: string | number;
    label: SolidComponent;
    closable: boolean;
  }
  const visibleTags = createMemo((): { visible: TagInfo[]; omitted: TagInfo[] } => {
    if (!isMultiple()) return { visible: [], omitted: [] };
    const vals = selectedValues();
    const map = optionMap();
    const maxTagCount = p.maxTagCount as number | 'responsive' | undefined;
    const maxTextLen = p.maxTagTextLength as number | undefined;

    const tags: TagInfo[] = vals.map(val => {
      const opt = map.get(val);
      let label: SolidComponent = opt?.label ?? String(val);
      if (maxTextLen && typeof label === 'string' && label.length > maxTextLen) {
        label = label.slice(0, maxTextLen) + '...';
      }
      return { value: val, label, closable: !p.disabled };
    });

    if (typeof maxTagCount === 'number' && tags.length > maxTagCount) {
      return { visible: tags.slice(0, maxTagCount), omitted: tags.slice(maxTagCount) };
    }

    return { visible: tags, omitted: [] };
  });

  const showClear = createMemo(() => {
    if (!p.allowClear) return false;
    if (p.disabled) return false;
    return selectedValues().length > 0;
  });

  const handleTriggerClick = (e: MouseEvent) => {
    if (p.disabled || p.loading) return;
    e.preventDefault();
    toggleDropdown();
  };

  const findOptionIndex = (target: EventTarget | null): number | null => {
    let el = target as HTMLElement | null;
    while (el) {
      const idx = el.dataset?.optionIndex;
      if (idx !== undefined) return Number(idx);

      if (el.classList?.contains('sel30')) return null;
      el = el.parentElement;
    }
    return null;
  };

  const handleListClick = (e: MouseEvent) => {
    const flatIdx = findOptionIndex(e.target);
    if (flatIdx === null) return;
    const opts = filteredOptions();
    const opt = opts[flatIdx];
    if (!opt || opt.disabled || (isMaxReached() && !isSelected(opt.value))) return;
    // In multiple mode, selecting an option re-renders the tag list (DOM mutation)
    // which can cause a spurious focusout. Suppress blur handling briefly.
    if (isMultiple()) suppressBlurUntil = performance.now() + 150;
    handleSelect(opt.value);
  };

  const renderOptionItem = (opt: FlatOption, flatIdx: number) => {
    const selected = () => isSelected(opt.value);
    const isActive = () => activeIndex() === flatIdx;
    const isDisabledOpt = () => opt.disabled || (isMaxReached() && !selected());

    const flattenData: FlattenOptionData = {
      label: opt.label,
      value: opt.value,
      disabled: opt.disabled,
      key: opt.value,
      groupLabel: opt.groupLabel,
    };

    const content = p.optionRender
      ? p.optionRender(flattenData, { index: flatIdx })
      : (opt.label as Element);

    return (
      <div
        data-option-index={flatIdx}
        class={cn(
          'sel31',
          selected() && 'sel33',
          isActive() && 'sel32',
          isDisabledOpt() && 'sel34',
          opt.groupLabel !== undefined && 'sel38',
          opt.class,
        )}
        title={opt.title}
      >
        <span class="sel35">{content}</span>
        <Show when={selected()}>
          <span class="sel36">
            {p.menuItemSelectedIcon ? (
              (p.menuItemSelectedIcon as Element)
            ) : (
              <Check size={14} color="var(--color)" stroke-width={3} />
            )}
          </span>
        </Show>
      </div>
    );
  };

  const dropdownContent = () => {
    const renderList = flatRenderList();

    if (renderList.length === 0) {
      return <div class="sel39">{p.notFoundContent as Element}</div>;
    }

    if (p.virtual) {
      return (
        <div
          ref={el => {
            requestAnimationFrame(() => setListRef(el));
          }}
          class={cn('sel30', getColor(p.color))}
          style={{ 'max-height': `${p.listHeight}px`, 'overflow-y': 'auto' }}
          onClick={handleListClick}
        >
          <div
            style={{
              height: `${virtualizer.getTotalSize()}px`,
              width: '100%',
              position: 'relative',
            }}
          >
            <For each={virtualizer.getVirtualItems()}>
              {virtualRow => {
                const item = renderList[virtualRow.index];
                return (
                  <div
                    data-index={virtualRow.index}
                    style={{
                      position: 'absolute',
                      top: 0,
                      left: 0,
                      width: '100%',
                      transform: `translateY(${virtualRow.start}px)`,
                    }}
                  >
                    {item.type === 'group' ? (
                      <div class="sel37">{item.groupLabel as Element}</div>
                    ) : (
                      renderOptionItem(item.option, item.flatIdx)
                    )}
                  </div>
                );
              }}
            </For>
          </div>
        </div>
      );
    }

    return (
      <div
        ref={el => setListRef(el)}
        class="sel30"
        style={{ 'max-height': `${p.listHeight}px` }}
        onClick={handleListClick}
      >
        <For each={renderList}>
          {item =>
            item.type === 'group' ? (
              <div class="sel37">{item.groupLabel as Element}</div>
            ) : (
              renderOptionItem(item.option, item.flatIdx)
            )
          }
        </For>
      </div>
    );
  };

  const renderTag = (tag: { value: string | number; label: SolidComponent; closable: boolean }) => (
    <SelectTag
      tag={tag}
      removeIcon={p.removeIcon as JSXElement}
      tagRender={p.tagRender as ((props: TagRenderProps) => JSXElement) | undefined}
      onRemove={handleRemoveTag}
    />
  );

  createEffect(
    on(dropdownOpen, open => {
      if (open && p.defaultActiveFirstOption) {
        const opts = filteredOptions();
        const idx = opts.findIndex(o => !o.disabled && (!isMaxReached() || isSelected(o.value)));
        setActiveIndex(idx >= 0 ? idx : -1);
      }
      if (!open) {
        setActiveIndex(-1);
      }
    }),
  );

  createEffect(
    on(
      () => currentSearchText(),
      () => {
        if (dropdownOpen() && p.defaultActiveFirstOption) {
          const opts = filteredOptions();
          const idx = opts.findIndex(o => !o.disabled && (!isMaxReached() || isSelected(o.value)));
          setActiveIndex(idx >= 0 ? idx : -1);
        }
      },
    ),
  );

  createEffect(
    on(listRef, el => {
      if (el && dropdownOpen()) {
        requestAnimationFrame(() => {
          if (p.virtual) virtualizer.measure();
          scrollToFirstSelected();
        });
      }
    }),
  );

  createEffect(
    on(
      () => dropdownOpen(),
      open => {
        if (open && showSearchEnabled()) {
          queueMicrotask(() => inputRef?.focus({ preventScroll: true }));
        }
      },
    ),
  );

  return (
    <Dropdown
      ref={el => (selectRootRef = el)}
      open={dropdownOpen()}
      blockScroll={p.blockScroll}
      position={p.placement === 'top' ? 'top' : 'bottom'}
      class={{
        trigger: `${p.disabled ? 'pointer-events-none' : ''} w-full`,
        content: cn(
          'border-c3 bg-base-100 rounded-box menu p-0',
          p.placement === 'bottom' ? 'mt-1 shadow-md' : 'shadow-md-top mb-1',
          p.class?.dropdownContent,
        ),
      }}
      triggerElement={
        <div
          ref={el => (triggerRef = el)}
          class={cn(
            selectVariants({ size: p.size, variant: p.variant }),
            getColor(p.color),
            dropdownOpen() && 'sel41 sel02',
            isMultiple() && 'sel40',
            p.class?.root,
            p.disabled && 'sel03',
          )}
          tabIndex={p.disabled ? -1 : 0}
          onClick={handleTriggerClick}
          onKeyDown={handleKeyDown}
          onFocus={handleFocus}
          onBlur={handleBlur}
          role="combobox"
          aria-expanded={dropdownOpen()}
          aria-haspopup="listbox"
        >
          <Show when={p.prefix}>
            <span class="sel11">{p.prefix as Element}</span>
          </Show>

          <div class="sel12">
            <Show
              when={isMultiple()}
              fallback={
                <div class="sel13">
                  <Show
                    when={selectedValues().length > 0}
                    fallback={
                      <span
                        class="sel15"
                        style={{
                          visibility: currentSearchText() ? 'hidden' : undefined,
                        }}
                      >
                        {p.placeholder}
                      </span>
                    }
                  >
                    <span
                      class="sel14"
                      style={{
                        visibility:
                          currentSearchText() && showSearchEnabled() ? 'hidden' : undefined,
                      }}
                    >
                      {selectedLabel()}
                    </span>
                  </Show>
                </div>
              }
            >
              <div class="sel16">
                <For each={visibleTags().visible}>{tag => renderTag(tag)}</For>

                <Show when={visibleTags().omitted.length > 0}>
                  <InnerTooltip
                    content={
                      <For each={visibleTags().omitted}>
                        {tag => (
                          <SelectTag
                            tag={tag}
                            removeIcon={p.removeIcon as JSXElement}
                            tagRender={
                              p.tagRender as ((props: TagRenderProps) => JSXElement) | undefined
                            }
                            onRemove={handleRemoveTag}
                          />
                        )}
                      </For>
                    }
                  >
                    <span class="sel17 sel20">
                      {(() => {
                        const placeholder = p.maxTagPlaceholder;
                        if (typeof placeholder === 'function') {
                          const omittedValues = visibleTags().omitted.map(t => ({
                            value: t.value,
                            label: t.label,
                          })) as LabeledValue[];
                          return placeholder(omittedValues) as Element;
                        }
                        if (placeholder) return placeholder;
                        return `+${visibleTags().omitted.length} more...`;
                      })()}
                    </span>
                  </InnerTooltip>
                </Show>

                <Show when={selectedValues().length === 0}>
                  <span class="sel15">{p.placeholder}</span>
                </Show>
              </div>
            </Show>
          </div>

          <div class="sel22">
            <Show when={showClear()}>
              <span class="sel26" onClick={handleClear}>
                <X class="m-auto" size={14} />
              </span>
            </Show>
            <Show when={!p.loading} fallback={<span class="sel25"></span>}>
              <span class={cn('sel23', dropdownOpen() && 'sel24')}>
                {p.suffixIcon ? (p.suffixIcon as Element) : <ChevronDown size={16} />}
              </span>
            </Show>
          </div>
        </div>
      }
    >
      <div
        role="listbox"
        class={getColor(p.color)}
        onMouseDown={e => {
          if ((e.target as HTMLElement)?.tagName !== 'INPUT') {
            e.preventDefault();
          }
        }}
      >
        <Show when={showSearchEnabled()}>
          <div class="flex items-center px-3 shadow-2xs">
            <Search size={14} />
            <input
              ref={ref => (inputRef = ref)}
              class="sel29"
              value={currentSearchText()}
              onInput={handleSearchInput}
              onKeyDown={handleKeyDown}
              onFocus={handleFocus}
              onBlur={handleBlur}
              disabled={p.disabled}
              autocomplete="off"
              role="combobox"
              aria-expanded={dropdownOpen()}
              aria-haspopup="listbox"
              aria-autocomplete="list"
              placeholder="Search..."
            />
          </div>
        </Show>
        {p.popupRender ? p.popupRender(dropdownContent()) : dropdownContent()}
      </div>
    </Dropdown>
  );
};
